// Map the many language ids a code sample can carry (shiki ids, aliases) onto a
// canonical icon name.
const ALIASES: Record<string, string> = {
  js: "javascript",
  jsx: "javascript",
  javascript: "javascript",
  ts: "typescript",
  tsx: "typescript",
  typescript: "typescript",
  py: "python",
  python: "python",
  go: "go",
  golang: "go",
  rb: "ruby",
  ruby: "ruby",
  php: "php",
  node: "node",
  nodejs: "node",
  "node.js": "node",
  shell: "shell",
  shellscript: "shell",
  sh: "shell",
  bash: "shell",
  zsh: "shell",
  console: "shell",
  powershell: "shell",
  cmd: "shell",
  curl: "curl",
};

/** Resolve a raw language/meta id to a canonical icon name, or null if none. */
export function resolveCodeLangName(lang?: string | null): string | null {
  if (!lang) return null;
  const key = lang.toLowerCase().trim().replace(/^language-/, "");
  const canon = ALIASES[key] ?? (CODE_LANG_ICONS[key] ? key : null);
  return canon && CODE_LANG_ICONS[canon] ? canon : null;
}

